const statusPedido = 'pago';

switch (statusPedido) {
  case 'pendente':
    console.log('Aguardando pagamento');
    break;
  case 'pago':
    console.log('Pagamento confirmado');
    break;
  case 'enviado':
    console.log('Pedido em transporte');
    break;
  default:
    console.log('Status desconhecido');
}
